import { defineStore } from 'pinia'
import { useUserStore } from './user'

export const useCartStore = defineStore('cart', {
  state: () => ({
    rawItems: [] as string[],
  }),
  getters: {
    items: (state) =>
      state.rawItems.reduce(
        (items, item) => {
          const existingItem = items.find((it) => it.name === item)

          if (!existingItem) {
            items.push({ name: item, amount: 1 })
          } else {
            existingItem.amount++
          }

          return items
        },
        [] as Array<{ name: string; amount: number }>
      ),
  },
  actions: {
    addItem(name: string) {
      this.rawItems.push(name)
    },

    removeItem(name: string) {
      const i = this.rawItems.lastIndexOf(name)
      if (i > -1) this.rawItems.splice(i, 1)
    },

    async purchaseItems() {
      const user = useUserStore()
      if (!user.name) return

      console.log('Purchasing', this.items)
      const n = this.items.length
      this.rawItems = []

      return n
    },
  },
})

interface User {
  id: string
}
type State<T extends string> = { type: T }
type AuthStateLoggingIn = State<'loggingIn'>
type AuthStateLoggedIn = State<'loggedIn'> & { user: User }
type AuthStateError = State<'error'> & { errorMsg: string }
type AuhtStateLoggedOut = State<'loggedOut'>

export type AuthState =
  | AuthStateLoggingIn
  | AuthStateLoggedIn
  | AuthStateError
  | AuhtStateLoggedOut

import { acceptHMRUpdate, defineStore } from 'pinia'

const delay = (t: number) => new Promise((r) => setTimeout(r, t))

export const useWholeStore = defineStore('whole', {
  state: (): AuthState => ({ type: 'loggedIn', user: { id: '1' } }),

  getters: {
    errorMsg: (state) => (state.type === 'error' ? state.errorMsg : ''),
  },

  actions: {
    async login() {
      try {
        await delay(1000)
        this.$patch({ type: 'loggedIn', user: { id: '1' } })
      } catch (e) {
        const error = e as Error
        this.$patch({ type: 'error', errorMsg: error.message })
      }
    },

    logout() {
      this.$patch({ type: 'loggedOut' })
    },
  },
})

if (import.meta.hot) {
  import.meta.hot.accept(acceptHMRUpdate(useWholeStore, import.meta.hot))
}

import { provide } from 'vue'

import type { InjectionKey, ObjectDirective, Ref } from 'vue'

type ForwardRefSetter = <T>(el: T) => void

export type ForwardRefInjectionContext = {
  setForwardRef: ForwardRefSetter
}

export const FORWARD_REF_INJECTION_KEY: InjectionKey<ForwardRefInjectionContext> =
  Symbol('elForwardRef')

export const useForwardRef = <T>(forwardRef: Ref<T | null>) => {
  const setForwardRef = ((el: T) => {
    forwardRef.value = el
  }) as ForwardRefSetter

  provide(FORWARD_REF_INJECTION_KEY, {
    setForwardRef,
  })
}

export const useForwardRefDirective = (
  setForwardRef: ForwardRefSetter
): ObjectDirective => {
  return {
    mounted(el) {
      setForwardRef(el)
    },
    updated(el) {
      setForwardRef(el)
    },
    unmounted() {
      setForwardRef(null)
    },
  }
}

export const withPropsDefaultsSetter = (target: any) => {
  const _p = target.props
  const props = isArray(_p) ? fromPairs(_p.map((key) => [key, {}])) : _p

  target.setPropsDefaults = (defaults: Record<string, any>) => {
    if (!props) {
      return
    }

    for (const [key, value] of Object.entries(defaults)) {
      const prop = props[key]

      if (!hasOwn(props, key)) {
        continue
      }

      if (isPlainObject(prop)) {
        // e.g. { type: String }
        props[key] = {
          ...prop,
          default: value,
        }
        continue
      }

      props[key] = {
        type: prop,
        default: value,
      }
    }

    target.props = props
  }
}

export const withInstall = <T, E extends Record<string, any>>(
  main: T,
  extra?: E
) => {
  ;(main as SFCWithInstall<T>).install = (app): void => {
    for (const comp of [main, ...Object.values(extra ?? {})]) {
      app.component(comp.name, comp)
    }
  }

  if (extra) {
    for (const [key, comp] of Object.entries(extra)) {
      ;(main as any)[key] = comp
    }
  }
  withPropsDefaultsSetter(main)
  return main as SFCWithInstall<T> & E
}

import type { Ref } from 'vue'
import { onBeforeUnmount, onMounted, watch } from 'vue'
import { resizeObserverManager } from 'vueuc'

export function useOnResize(
  elRef: Ref<HTMLElement | null>,
  onResize: (() => void) | undefined
): void {
  // it needn't be reactive since it's for internal usage
  if (onResize) {
    onMounted(() => {
      const { value: el } = elRef
      if (el) {
        resizeObserverManager.registerHandler(el, onResize)
      }
    })

    // avoid memory leak
    watch(
      elRef,
      (_, oldEl) => {
        if (oldEl) {
          resizeObserverManager.unregisterHandler(oldEl)
        }
      },
      {
        deep: false
      }
    )

    onBeforeUnmount(() => {
      const { value: el } = elRef
      if (el) {
        resizeObserverManager.unregisterHandler(el)
      }
    })
  }
}

import { unref, ref, watchEffect, Ref, onScopeDispose } from 'vue'

export function useCachedRequest<T, U>(
  keySource: Ref<U>,
  getter: (key: U) => Promise<T>
) {
  const data = ref<T>()
  const isLoading = ref(false)
  const isReady = ref(false)
  const error = ref<Error | undefined>()

  const cache = new Map<U, T>()

  onScopeDispose(() => {
    cache.clear()
  })

  watchEffect(async () => {
    const key = unref(keySource)
    isReady.value = false
    isLoading.value = true

    if (cache.has(key)) {
      data.value = cache.get(key)!
      isReady.value = true
    }

    getter(key)
      .then((newData) => {
        cache.set(key, newData)
        data.value = newData
        isReady.value = true
      })
      .catch((err) => {
        error.value = err
      })
      .finally(() => {
        isLoading.value = false
      })
  })

  return { data, error, isLoading, isReady }
}

import type { ShallowOrDeepRef } from '@vueuse/shared'
import type { Ref, WatchOptions } from 'vue'
import type { ConfigurableDeepRefs } from '../_configurable'
import { createRef } from '@vueuse/shared'
import { watch } from 'vue'

export interface UseCachedOptions<D extends boolean = true> extends ConfigurableDeepRefs<D>, WatchOptions {}

export function useCached<T, D extends boolean = true>(
  refValue: Ref<T>,
  comparator: (newSourceValue: T, cachedValue: T) => boolean = (newSourceValue, cachedValue) => newSourceValue === cachedValue,
  options?: UseCachedOptions<D>,
): UseCachedReturn<T, D> {
  const { deepRefs = true as D, ...watchOptions } = options || {}
  const cachedValue = createRef(refValue.value, deepRefs)

  watch(() => refValue.value, (value) => {
    if (!comparator(value, cachedValue.value))
      cachedValue.value = value
  }, watchOptions)

  return cachedValue
}

export type UseCachedReturn<T = any, D extends boolean = true> = ShallowOrDeepRef<T, D>

import { nav } from '~/content'

const navLookup = nav.reduce(
  (obj, section) => ({ ...obj, [section.base.replace('/', '')]: section }),
  {}
)

// @vue/component
export default {
  name: 'BVBreadcrumbs',
  computed: {
    items() {
      const items = [{ text: 'Home', to: '/' }, { text: 'Docs', to: '/docs' }]

      const section = this.$route.name.split('-')[1] || ''
      if (section) {
        const sectionMeta = navLookup[section] || {}

        items.push({
          text: sectionMeta.title || section,
          to: ['/docs', section].join('/')
        })

        const slug = this.$route.params.slug || ''
        if (slug) {
          const pagesMeta = sectionMeta.pages || {}

          items.push({
            text: (pagesMeta[slug] || {}).title || slug,
            to: ['/docs', section, slug].join('/')
          })
        }
      }

      return items
    }
  },
  render(h) {
    return h('nav', { attrs: { 'aria-label': 'Breadcrumbs' } }, [
      h('b-breadcrumb', {
        staticClass: 'd-inline-flex my-0 px-2 py-1 bg-transparent',
        props: { items: this.items }
      })
    ])
  }
}

import { extend, mergeData } from '../../vue'
